// Compute week-over-week trends per campaign from the Decision History tab
const portfolio = $('📦 Aggregate Portfolio1').first().json;
const historyRows = $input.all().map(i => i.json).filter(r => r && r.Campaign);
const num = (v) => { const n = parseFloat(String(v).replace(/[^0-9.\-]/g,'')); return isNaN(n)?0:n; };

// Group history by campaign name, take last 7 entries per campaign
const byCampaign = {};
historyRows.forEach(r => {
  const name = r.Campaign;
  if (!byCampaign[name]) byCampaign[name] = [];
  byCampaign[name].push({
    date: r.Date || '',
    roas: num(r.ROAS),
    ctr: num(r.CTR),
    cpa: num(r.CPA),
    spend: num(r.Spend),
    revenue: num(r.Revenue),
    action: r.Action || ''
  });
});

// For each campaign, compute trend signals
const trends = {};
Object.keys(byCampaign).forEach(name => {
  const hist = byCampaign[name].slice(-7); // last 7 runs
  if (hist.length < 2) {
    trends[name] = { runs: hist.length, roasTrend: 'insufficient_data', avgRoas: hist[0]?.roas || 0, trendNote: 'first run' };
    return;
  }
  const oldest = hist[0].roas;
  const latest = hist[hist.length - 1].roas;
  const avgRoas = +(hist.reduce((s, h) => s + h.roas, 0) / hist.length).toFixed(2);
  const avgCtr = +(hist.reduce((s, h) => s + h.ctr, 0) / hist.length).toFixed(2);
  const delta = oldest > 0 ? +(((latest - oldest) / oldest) * 100).toFixed(0) : 0;
  let trend = 'flat';
  if (delta >= 15) trend = 'accelerating';
  else if (delta <= -15) trend = 'decelerating';
  // Streak: count consecutive PAUSE/UNDERPERFORM decisions
  const recentPauses = hist.slice(-3).filter(h => h.action === 'PAUSE').length;
  trends[name] = {
    runs: hist.length,
    avgRoas, avgCtr,
    roasTrend: trend,
    deltaPct: delta,
    oldestRoas: oldest,
    latestRoas: latest,
    recentPauseStreak: recentPauses,
    trendNote: `${trend} (${delta>=0?'+':''}${delta}% over ${hist.length} runs)`
  };
});

// Portfolio-level trend
const portfolioHistory = [];
const byDate = {};
historyRows.forEach(r => {
  if (!byDate[r.Date]) byDate[r.Date] = { spend:0, revenue:0 };
  byDate[r.Date].spend += num(r.Spend);
  byDate[r.Date].revenue += num(r.Revenue);
});
Object.keys(byDate).forEach(d => {
  const dd = byDate[d];
  portfolioHistory.push({ date: d, roas: dd.spend>0?+(dd.revenue/dd.spend).toFixed(2):0, spend: dd.spend, revenue: dd.revenue });
});

return [{ json: { ...portfolio, campaignTrends: trends, portfolioHistory: portfolioHistory.slice(-7), historyCount: historyRows.length } }];

// Build the anomaly detection prompt - looks for things rule-logic misses
const d = $input.first().json;
const trends = d.campaignTrends || {};
const campaignSummary = d.campaigns.map(c => {
  const t = trends[c.campaignName] || {};
  return {
    name: c.campaignName,
    platform: c.platform,
    today: { roas: c.roas, ctr: c.ctr, cpa: c.cpa, spend: c.spend, revenue: c.revenue, conversions: c.conversions, impressions: c.impressions, clicks: c.clicks },
    history: t.runs > 0 ? { avg_roas: t.avgRoas, trend: t.roasTrend, delta_pct: t.deltaPct, runs: t.runs } : 'no_history'
  };
});

const prompt = `You are a senior performance marketing analyst with a sharp eye for anomalies. Scan these campaigns and detect ANYTHING UNUSUAL that rule-based logic might miss.

Look for:
- TRACKING_ISSUES: spend high but conversions suspiciously low (pixel/tracking broken?)
- DELIVERY_ISSUES: zero or near-zero impressions despite budget (campaign approval/delivery problem?)
- VIRAL_SPIKE: sudden CTR or conversion spike vs history (something hit a nerve - investigate why)
- AUDIENCE_FATIGUE: rising CPM + falling CTR + many days running (creative burned out)
- BUDGET_PACING: spend is far from daily budget (under-pacing = missed opportunity; full-pacing early = will run out)
- ATTRIBUTION_GAP: revenue swings massively while spend is stable (attribution lag or tracking issue)
- DUPLICATE_TARGETING: two campaigns with similar metrics likely fighting for same audience
- WINNING_PATTERN: any campaign showing strong upward momentum worth doubling down on

CAMPAIGN DATA WITH HISTORY:
${JSON.stringify(campaignSummary, null, 1)}

Return EXACT JSON:
{
  "anomalies": [
    { "type": "TRACKING_ISSUES | DELIVERY_ISSUES | VIRAL_SPIKE | AUDIENCE_FATIGUE | BUDGET_PACING | ATTRIBUTION_GAP | DUPLICATE_TARGETING | WINNING_PATTERN",
      "campaign": "campaign name",
      "severity": "critical | high | medium | low",
      "finding": "one sharp sentence on what's unusual",
      "recommended_check": "what to investigate or do next" }
  ],
  "opportunities": [
    { "campaign": "name", "opportunity": "what to capitalize on", "how": "specific action" }
  ],
  "hidden_risks": [
    "plain-English risk that isn't obvious from numbers alone"
  ],
  "anomaly_summary": "2-3 sentence executive summary of what's hiding in the data"
}

If nothing is anomalous, return empty arrays. Don't fabricate. Indian D2C context. Return ONLY valid JSON, no markdown.`;

return [{ json: { ...d, anomalyPrompt: prompt } }];

const aiResp = $input.first().json;
const d = $('🔧 Build Anomaly Prompt').first().json;
let anomalies = { anomalies: [], opportunities: [], hidden_risks: [], anomaly_summary: 'Scan complete - no anomalies detected.' };
try {
  let raw = '';
  const parts = aiResp?.candidates?.[0]?.content?.parts || [];
  for (const p of parts) { if (p && p.text) raw += p.text; }
  if (raw) {
    let t = raw.replace(/```json/gi,'').replace(/```/g,'').trim();
    const s = t.indexOf('{'), e = t.lastIndexOf('}');
    if (s>=0 && e>s) t = t.substring(s, e+1);
    anomalies = JSON.parse(t);
  }
} catch(e) {}
return [{ json: { ...d, anomalyReport: anomalies } }];

// Compute concrete budget reallocation from decisions
const d = $input.first().json;
const anomalyData = $('🔀 Parse Anomalies').first().json;
const trends = anomalyData.campaignTrends || {};
const anomalyReport = anomalyData.anomalyReport || { anomalies: [], opportunities: [], hidden_risks: [] };

// Recovered budget from PAUSEs
const pausedBudget = d.final
  .filter(c => c.decision.action === 'PAUSE')
  .reduce((s, c) => s + c.budget, 0);

// Star campaigns to scale
const scaleTargets = d.final.filter(c => c.decision.action === 'SCALE');
// MAINTAIN campaigns with strong ROAS that could absorb more
const maintainStars = d.final.filter(c => c.decision.action === 'MAINTAIN' && c.roas >= c.targetRoas * 1.2);

// Build reallocation plan
const reallocation = { recovered_from_pauses: pausedBudget, moves: [], reserve_for_testing: 0 };
let remaining = pausedBudget;

scaleTargets.forEach(c => {
  const suggestedIncrease = Math.round(c.budget * 0.25);
  const allocation = Math.min(suggestedIncrease, remaining);
  if (allocation > 0) {
    reallocation.moves.push({
      campaign: c.campaignName,
      action: 'INCREASE',
      from_budget: c.budget,
      to_budget: c.budget + allocation,
      added: allocation,
      reason: `Scale star (ROAS ${c.roas}x vs target ${c.targetRoas}x)`
    });
    remaining -= allocation;
  }
});
maintainStars.forEach(c => {
  const suggestedIncrease = Math.round(c.budget * 0.15);
  const allocation = Math.min(suggestedIncrease, remaining);
  if (allocation > 0) {
    reallocation.moves.push({
      campaign: c.campaignName,
      action: 'INCREASE',
      from_budget: c.budget,
      to_budget: c.budget + allocation,
      added: allocation,
      reason: `Healthy performer with room to grow (ROAS ${c.roas}x)`
    });
    remaining -= allocation;
  }
});
reallocation.reserve_for_testing = Math.max(0, remaining);
reallocation.total_allocated = pausedBudget - remaining;

// Compute projected impact
const expectedRoas = scaleTargets.length > 0 ? scaleTargets.reduce((s,c)=>s+c.roas,0)/scaleTargets.length : 0;
const projectedExtraRevenue = Math.round(reallocation.total_allocated * expectedRoas);
reallocation.projected_extra_revenue = projectedExtraRevenue;
reallocation.assumption = `Assuming new budget converts at ${expectedRoas.toFixed(2)}x (avg of scaled campaigns)`;

return [{ json: { ...d, campaignTrends: trends, anomalyReport, reallocation } }];

// Compute derived performance metrics + flag status for every campaign
// Expected sheet columns (each row = one ad campaign/adset for the latest day):
// Campaign Name, Platform, Status, Daily Budget, Spend, Impressions, Clicks,
// Conversions, Revenue, Target ROAS, Headline, Primary Text, Yesterday Spend,
// Yesterday Revenue, Days Running, Creative

const rows = $input.all();
const num = (v) => { const n = parseFloat(String(v).replace(/[^0-9.\-]/g, '')); return isNaN(n) ? 0 : n; };

const campaigns = rows.map(r => {
  const d = r.json;
  const spend = num(d['Spend']);
  const revenue = num(d['Revenue']);
  const impressions = num(d['Impressions']);
  const clicks = num(d['Clicks']);
  const conversions = num(d['Conversions']);
  const budget = num(d['Daily Budget']);
  const targetRoas = num(d['Target ROAS']) || 3;
  const yRevenue = num(d['Yesterday Revenue']);
  const ySpend = num(d['Yesterday Spend']);
  const daysRunning = num(d['Days Running']) || 1;

  // Core metrics
  const roas = spend > 0 ? +(revenue / spend).toFixed(2) : 0;
  const ctr = impressions > 0 ? +((clicks / impressions) * 100).toFixed(2) : 0;
  const cpc = clicks > 0 ? +(spend / clicks).toFixed(2) : 0;
  const cpa = conversions > 0 ? +(spend / conversions).toFixed(2) : 0;
  const convRate = clicks > 0 ? +((conversions / clicks) * 100).toFixed(2) : 0;
  const budgetUsed = budget > 0 ? +((spend / budget) * 100).toFixed(0) : 0;

  // Trend vs yesterday
  const yRoas = ySpend > 0 ? +(yRevenue / ySpend).toFixed(2) : 0;
  const roasDelta = yRoas > 0 ? +(((roas - yRoas) / yRoas) * 100).toFixed(0) : 0;

  // Health classification (rule-based pre-screen; AI makes the final call)
  let health = 'healthy';
  if (roas < 1) health = 'critical';            // losing money
  else if (roas < targetRoas * 0.7) health = 'underperforming';
  else if (roas >= targetRoas * 1.5) health = 'star';

  return {
    json: {
      campaignName: d['Campaign Name'] || 'Unnamed',
      platform: d['Platform'] || 'Unknown',
      status: d['Status'] || 'Active',
      budget, spend, revenue, impressions, clicks, conversions,
      roas, ctr, cpc, cpa, convRate, budgetUsed,
      targetRoas, roasDelta, daysRunning, health,
      headline: d['Headline'] || '',
      primaryText: d['Primary Text'] || '',
      creative: d['Creative'] || ''
    }
  };
});

return campaigns;

// Aggregate all campaigns into ONE payload for the AI analyst
const all = $input.all().map(i => i.json);

const totalSpend = all.reduce((s, c) => s + c.spend, 0);
const totalRevenue = all.reduce((s, c) => s + c.revenue, 0);
const portfolioRoas = totalSpend > 0 ? +(totalRevenue / totalSpend).toFixed(2) : 0;

return [{ json: {
  campaigns: all,
  campaignCount: all.length,
  totalSpend: +totalSpend.toFixed(0),
  totalRevenue: +totalRevenue.toFixed(0),
  portfolioRoas,
  runDate: new Date().toLocaleDateString('en-IN', { weekday:'long', year:'numeric', month:'long', day:'numeric' })
}}];

// Build the AI Analyst prompt - enriched with week-over-week trends + anomaly findings
const d = $input.first().json;
const c = JSON.stringify(d.campaigns, null, 1);
const trends = d.campaignTrends || {};
const anomalyReport = d.anomalyReport || { anomalies: [], opportunities: [] };

// Format trends for prompt
const trendsText = Object.keys(trends).length > 0 ?
  Object.entries(trends).map(([name, t]) =>
    `- ${name}: avg ROAS ${t.avgRoas}x over ${t.runs} runs, trend ${t.roasTrend} (${t.deltaPct>=0?'+':''}${t.deltaPct}%)`
  ).join('\n') : 'No historical data yet (first run).';

const anomalyText = anomalyReport.anomalies?.length > 0 ?
  anomalyReport.anomalies.map(a => `- [${a.severity?.toUpperCase()}] ${a.campaign}: ${a.finding}`).join('\n') : 'No anomalies detected.';

const prompt = `You are a senior performance marketing analyst managing the ad budget for an Indian D2C brand. Analyze TODAY's campaign data and decide the optimal action for EACH campaign.

PORTFOLIO SNAPSHOT (${d.runDate}):
Total Spend: INR ${d.totalSpend}
Total Revenue: INR ${d.totalRevenue}
Portfolio ROAS: ${d.portfolioRoas}x
Campaigns: ${d.campaignCount}

CAMPAIGN DATA:
${c}

WEEK-OVER-WEEK TRENDS (use these for context, not just today's snapshot):
${trendsText}

ANOMALIES DETECTED:
${anomalyText}

For EACH campaign decide ONE action:
- SCALE: performing well above target, increase budget 20-30%
- MAINTAIN: on target, keep as is
- REFRESH_CREATIVE: decent metrics but CTR low or fatiguing (running many days, falling ROAS) - keep targeting, rewrite the ad copy
- PAUSE: ROAS below 1 (losing money) or far below target with no upside
- WATCH: too early to judge (low spend / few days) - monitor

CRITICAL: Use the trend data. A campaign at 3x ROAS today but trending downward for 5 days = REFRESH_CREATIVE (not MAINTAIN). A campaign with PAUSE streak in recent history but suddenly up = WATCH carefully.

Decision logic:
- ROAS < 1 = losing money = usually PAUSE
- Low CTR (<1%) with decent ROAS = REFRESH_CREATIVE
- High ROAS (>= 1.5x target) = SCALE
- Falling ROAS trend (decelerating) + many days running = creative fatigue = REFRESH_CREATIVE
- Consider budget pacing and statistical significance (don't pause on tiny spend)

Return EXACT JSON:
{
  "portfolio_summary": "2-3 sentence plain-English summary of overall performance today, referencing trends if notable",
  "portfolio_health": "healthy | needs_attention | critical",
  "daily_spend_recommendation": "Brief recommendation on total budget allocation",
  "decisions": [
    {
      "campaign_name": "exact name",
      "action": "SCALE | MAINTAIN | REFRESH_CREATIVE | PAUSE | WATCH",
      "reason": "one sharp sentence why (reference trend if relevant)",
      "specific_step": "the exact action to take, e.g. 'Increase daily budget from 2000 to 2600'",
      "priority": "high | medium | low",
      "needs_creative_rewrite": true
    }
  ],
  "top_action_today": "The single most important thing to do right now",
  "urgent_alert": "If any campaign is bleeding money badly, state it here, else empty string"
}

Set needs_creative_rewrite=true ONLY for REFRESH_CREATIVE actions. Indian D2C context, INR. Return ONLY valid JSON, no markdown, no backticks.`;

return [{ json: { ...d, analystPrompt: prompt } }];

// Parse the analyst's decisions with robust extraction + fallback
const aiResp = $input.first().json;
const d = $('🔀 Parse Anomalies').first().json;

let analysis = {};
try {
  let raw = '';
  const parts = aiResp?.candidates?.[0]?.content?.parts || [];
  for (const p of parts) { if (p && p.text) raw += p.text; }
  if (!raw) raw = '{}';
  let t = raw.replace(/```json/gi, '').replace(/```/g, '').trim();
  const s = t.indexOf('{'), e = t.lastIndexOf('}');
  if (s >= 0 && e > s) t = t.substring(s, e + 1);
  analysis = JSON.parse(t);
} catch (e) {
  // Fallback: rule-based decisions from health flags
  analysis = {
    portfolio_summary: 'Automated rule-based analysis (AI parse failed).',
    portfolio_health: d.portfolioRoas < 1 ? 'critical' : d.portfolioRoas < 2 ? 'needs_attention' : 'healthy',
    daily_spend_recommendation: 'Review manually.',
    decisions: d.campaigns.map(c => ({
      campaign_name: c.campaignName,
      action: c.health === 'critical' ? 'PAUSE' : c.health === 'star' ? 'SCALE' : c.health === 'underperforming' ? 'REFRESH_CREATIVE' : 'MAINTAIN',
      reason: 'Rule-based on ROAS ' + c.roas + 'x',
      specific_step: 'Review campaign',
      priority: c.health === 'critical' ? 'high' : 'medium',
      needs_creative_rewrite: c.health === 'underperforming'
    })),
    top_action_today: 'Review the dashboard.',
    urgent_alert: d.campaigns.some(c => c.roas < 1) ? 'One or more campaigns are losing money.' : ''
  };
}

// Merge each decision with its full campaign metrics for reporting
const decMap = {};
(analysis.decisions || []).forEach(dec => { decMap[dec.campaign_name] = dec; });
const enriched = d.campaigns.map(c => ({
  ...c,
  decision: decMap[c.campaignName] || { action: 'WATCH', reason: 'No decision returned', specific_step: '-', priority: 'low', needs_creative_rewrite: false }
}));

// Campaigns needing a creative rewrite
const needRewrite = enriched.filter(c => c.decision.needs_creative_rewrite || c.decision.action === 'REFRESH_CREATIVE');

return [{ json: { ...d, analysis, enriched, needRewrite, hasRewrites: needRewrite.length > 0 } }];

// Build the creative-rewrite prompt (only the fatiguing campaigns)
const d = $input.first().json;
if (!d.hasRewrites) { return [{ json: { ...d, rewritePrompt: '', skipRewrite: true } }]; }

const items = d.needRewrite.map(c => ({
  campaign: c.campaignName,
  platform: c.platform,
  current_headline: c.headline,
  current_text: c.primaryText,
  why: c.decision.reason,
  roas: c.roas, ctr: c.ctr
}));

const prompt = `You are an award-winning Indian D2C ad copywriter. These ad creatives are fatiguing (low CTR / falling ROAS). Rewrite each with a FRESH angle while keeping the same product and offer.

FATIGUING ADS:
${JSON.stringify(items, null, 1)}

For EACH, write a fresh version with a different hook/angle than the current one. Return EXACT JSON:
{
  "rewrites": [
    {
      "campaign": "exact campaign name",
      "new_headline": "fresh headline, under 40 chars",
      "new_primary_text": "fresh primary text, under 125 words, new angle",
      "angle_used": "what new angle this takes (e.g. social proof, urgency, problem-agitation)",
      "why_better": "one line on why this should outperform the old one"
    }
  ]
}
Indian English, INR. Return ONLY valid JSON, no markdown, no backticks.`;

return [{ json: { ...d, rewritePrompt: prompt, skipRewrite: false } }];

// Parse rewrites, attach to decisions, build everything the report needs
const aiResp = $input.first().json;
const d = $('🔀 Parse Decisions1').first().json;

let rewrites = [];
try {
  let raw = '';
  const parts = aiResp?.candidates?.[0]?.content?.parts || [];
  for (const p of parts) { if (p && p.text) raw += p.text; }
  if (raw) {
    let t = raw.replace(/```json/gi, '').replace(/```/g, '').trim();
    const s = t.indexOf('{'), e = t.lastIndexOf('}');
    if (s >= 0 && e > s) t = t.substring(s, e + 1);
    const parsed = JSON.parse(t);
    rewrites = parsed.rewrites || [];
  }
} catch (e) { rewrites = []; }

const rwMap = {};
rewrites.forEach(r => { rwMap[r.campaign] = r; });

// Action counts for the report header
const counts = { SCALE:0, MAINTAIN:0, REFRESH_CREATIVE:0, PAUSE:0, WATCH:0 };
d.enriched.forEach(c => { const a = c.decision.action; if (counts[a] !== undefined) counts[a]++; });

// Attach rewrite text to enriched campaigns
const final = d.enriched.map(c => ({ ...c, rewrite: rwMap[c.campaignName] || null }));

return [{ json: { ...d, rewrites, rwMap, counts, final } }];

// Build the daily optimization brief (premium dark HTML email) - ENHANCED
const d = $input.first().json;
const a = d.analysis;
const trends = d.campaignTrends || {};
const ar = d.anomalyReport || { anomalies: [], opportunities: [], hidden_risks: [], anomaly_summary: '' };
const realloc = d.reallocation || { recovered_from_pauses:0, moves:[], reserve_for_testing:0, total_allocated:0, projected_extra_revenue:0 };

const c = {bg:'#0d1117',card:'#161b22',border:'#1e293b',orange:'#f97316',blue:'#2563eb',teal:'#0d9488',green:'#22c55e',purple:'#8b5cf6',yellow:'#f59e0b',pink:'#ec4899',red:'#ef4444',white:'#ffffff',light:'#e2e8f0',gray:'#94a3b8'};

const actionColor = { SCALE:c.green, MAINTAIN:c.blue, REFRESH_CREATIVE:c.yellow, PAUSE:c.red, WATCH:c.gray };
const actionEmoji = { SCALE:'📈', MAINTAIN:'✅', REFRESH_CREATIVE:'🔄', PAUSE:'⏸️', WATCH:'👀' };
const sevColor = { critical:c.red, high:c.orange, medium:c.yellow, low:c.gray };
const healthColor = a.portfolio_health === 'healthy' ? c.green : a.portfolio_health === 'critical' ? c.red : c.yellow;

// Trend badge helper
const trendBadge = (campaignName) => {
  const t = trends[campaignName];
  if (!t || t.runs < 2) return '<span style="display:inline-block;background:'+c.gray+'22;color:'+c.gray+';padding:2px 8px;border-radius:10px;font-size:10px;margin-left:6px;">NEW</span>';
  if (t.roasTrend === 'accelerating') return '<span style="display:inline-block;background:'+c.green+'22;color:'+c.green+';padding:2px 8px;border-radius:10px;font-size:10px;margin-left:6px;">↑ '+t.deltaPct+'% (7d)</span>';
  if (t.roasTrend === 'decelerating') return '<span style="display:inline-block;background:'+c.red+'22;color:'+c.red+';padding:2px 8px;border-radius:10px;font-size:10px;margin-left:6px;">↓ '+t.deltaPct+'% (7d)</span>';
  return '<span style="display:inline-block;background:'+c.blue+'22;color:'+c.blue+';padding:2px 8px;border-radius:10px;font-size:10px;margin-left:6px;">flat (7d)</span>';
};

// Decision rows with trend badges
const rows = d.final.map(camp => {
  const dec = camp.decision;
  const col = actionColor[dec.action] || c.gray;
  const em = actionEmoji[dec.action] || '•';
  let rewriteBlock = '';
  if (camp.rewrite) {
    rewriteBlock = '<div style="margin-top:10px;background:#1a1f29;border-radius:6px;padding:10px;border-left:3px solid '+c.yellow+';">' +
      '<p style="color:'+c.yellow+';font-size:10px;margin:0 0 6px;text-transform:uppercase;letter-spacing:1px;">🔄 FRESH CREATIVE (' + (camp.rewrite.angle_used||'') + ')</p>' +
      '<p style="color:'+c.white+';font-size:13px;font-weight:600;margin:0 0 4px;">' + (camp.rewrite.new_headline||'') + '</p>' +
      '<p style="color:'+c.light+';font-size:12px;margin:0 0 6px;line-height:1.5;">' + (camp.rewrite.new_primary_text||'') + '</p>' +
      '<p style="color:'+c.gray+';font-size:11px;margin:0;font-style:italic;">' + (camp.rewrite.why_better||'') + '</p></div>';
  }
  return '<div style="background:'+c.card+';border-radius:8px;padding:14px;margin:0 0 12px;border:1px solid '+c.border+';border-left:4px solid '+col+';">' +
    '<table style="width:100%;border-collapse:collapse;"><tr>' +
    '<td style="vertical-align:top;"><p style="color:'+c.white+';font-size:14px;font-weight:700;margin:0;">' + camp.campaignName + trendBadge(camp.campaignName) + '</p>' +
    '<p style="color:'+c.gray+';font-size:11px;margin:2px 0 0;">' + camp.platform + ' • ' + camp.daysRunning + ' days running</p></td>' +
    '<td style="text-align:right;vertical-align:top;"><span style="background:'+col+';color:#fff;padding:4px 12px;border-radius:12px;font-size:11px;font-weight:700;">' + em + ' ' + dec.action.replace('_',' ') + '</span></td>' +
    '</tr></table>' +
